const staticData = $getWorkflowStaticData('global');
const profiles = staticData.commute_profiles || {};

const now = new Date();
const options = { timeZone: 'Asia/Kolkata', hour12: false, hour: '2-digit', minute: '2-digit', weekday: 'long' };
const formatter = new Intl.DateTimeFormat('en-US', options);
const parts = formatter.formatToParts(now);
let dayOfWeek = '', currentHour = '', currentMinute = '';
for(let p of parts) {
  if (p.type === 'weekday') dayOfWeek = p.value;
  if (p.type === 'hour') currentHour = p.value;
  if (p.type === 'minute') currentMinute = p.value;
}

const currentISTMinutes = parseInt(currentHour) * 60 + parseInt(currentMinute);

const activeCommutes = [];

for (const [phone, profile] of Object.entries(profiles)) {
  const commuteDays = Array.isArray(profile.commute_days) ? profile.commute_days : JSON.parse(profile.commute_days || '[]');
  if (!commuteDays.includes(dayOfWeek)) continue;

  const [ph, pm] = (profile.commute_time || '00:00').split(':');
  const profileMinutes = parseInt(ph) * 60 + parseInt(pm);

  // Triggers 15 minutes BEFORE commute time
  if (currentISTMinutes === profileMinutes - 15) {
    activeCommutes.push({
      phoneNumber: phone,
      origin: profile.commute_origin,
      destination: profile.commute_destination,
      scheduled_time: profile.commute_time
    });
  }
}

return [{ json: { activeCommutes } }];

const gtfs = $('Load GTFS').first().json;
const weather = $('Fetch Weather').first().json;
const pre = $('Check Profiles').first().json;
const activeCommutes = pre.activeCommutes;

const stationsObj = gtfs.stations || {};
const stations = Object.entries(stationsObj).map(([name, data]) => ({ name, ...data }));
const line = gtfs.line || [];
const schedule = gtfs.schedule || [];
const fares = gtfs.fares || {};

function haversine(lat1, lon1, lat2, lon2) {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
    return R * 2 * Math.asin(Math.sqrt(a));
}
function matchStation(searchName) {
    if (!searchName) return null;
    const s1 = String(searchName).toLowerCase().replace(/[^a-z0-9]/g, '');
    for (const st of stations) {
        const s2 = String(st.name).toLowerCase().replace(/[^a-z0-9]/g, '');
        if (s1 === s2) return st;  
    }
    for (const st of stations) {
        const s2 = String(st.name).toLowerCase().replace(/[^a-z0-9]/g, '');
        if (s1.includes(s2) || s2.includes(s1)) return st;
    }
    return null;
}

const now = new Date();
const utcNow = now.getTime() + (now.getTimezoneOffset() * 60000);
const istNow = new Date(utcNow + (330 * 60000));
const arrivalAtStation = new Date(istNow.getTime() + (15 * 60000));
const aH = arrivalAtStation.getHours(), aM = arrivalAtStation.getMinutes(), aS = arrivalAtStation.getSeconds();
const arrivalTimeStr = `${String(aH).padStart(2,'0')}:${String(aM).padStart(2,'0')}:${String(aS).padStart(2,'0')}`;

const outputItems = [];

for (const commute of activeCommutes) {
    const origin = commute.origin;
    const dest = commute.destination;
    const entryStation = matchStation(origin);
    const exitStation = matchStation(dest);

    if (!entryStation || !exitStation) continue;
    if (entryStation.name === exitStation.name) continue;

    let stopCount = 0;
    const entryIndex = line.indexOf(entryStation.name);
    const exitIndex = line.indexOf(exitStation.name);
    if (entryIndex !== -1 && exitIndex !== -1) stopCount = Math.abs(entryIndex - exitIndex);

    let entrySchedules = [];
    if (Array.isArray(schedule)) {
        entrySchedules = schedule.filter(s => s.stop_id === entryStation.id || s.stop_id === entryStation.name);
    } else if (schedule[entryStation.id] || schedule[entryStation.name]) {
        const arr = schedule[entryStation.id] || schedule[entryStation.name];
        entrySchedules = arr.map(t => ({ stop_id: entryStation.id, departure_time: t.time || t.departure_time || t }));
    }
    entrySchedules = entrySchedules.filter(s => (s.departure_time || '') >= arrivalTimeStr);
    entrySchedules.sort((a,b) => (a.departure_time||'').localeCompare(b.departure_time||''));

    const nextTrain = entrySchedules.length > 0 ? entrySchedules[0] : null;
    let nextDepartureTime = 'N/A';
    if (nextTrain) nextDepartureTime = (nextTrain.departure_time || '').slice(0,5);

    let fare = 0;
    const key = `${entryStation.zone}_${exitStation.zone}`;
    if (fares[key]) fare = fares[key];
    else if (fares[stopCount]) fare = fares[stopCount];
    else {
        const dist = haversine(entryStation.lat, entryStation.lon, exitStation.lat, exitStation.lon);
        fare = (dist<=2?10:dist<=5?20:dist<=10?30:dist<=15?40:dist<=20?50:60);
    }

    const weatherTip = weather.weather && weather.weather[0] ? `🌤 Weather in Kochi: ${weather.weather[0].main}, ${Math.round(weather.main.temp)}°C` : '';

    const message = `Good morning! 🚇 It's almost time for your ${commute.scheduled_time} commute.\n\n📍 ${entryStation.name} → ${exitStation.name}\n💰 Fare: ₹${fare}\n\n🚆 The next train leaves at ${nextDepartureTime}.\n\n${weatherTip}\n\nHave a great trip!`;

    outputItems.push({
        json: {
            phoneNumber: commute.phoneNumber,
            outboundMessage: message
        }
    });
}

return outputItems;
